import './DatePickerRangeSplit.scss';

import { MaskField } from ':components/MaskField';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ChangeEvent } from 'react';
import React, { forwardRef, useCallback, useEffect, useRef } from 'react';

import { IconButton } from '../../IconButton';
import { TextField } from '../../TextField';
import { CalendarRange } from '../Calendar';
import { EMPTY_DATE, RU_FORMAT_PATTERN } from '../Calendar/constants';
import { maskRuDate, shouldClearOnCloseSplitInputs } from '../helpers/rangeInputHelpers';
import { usePrevious } from '../hooks/use-previous';
import { useDatePicker } from '../useDatePicker';
import {
	maskConfig as defaultMaskConfig,
	maskConfigTime as defaultMaskConfigTime,
	formatDateToISOWithTimeZone,
	isFilledDate,
	maskDate,
} from '../utils';
import type { DatePickerRangeSplitProps } from './DatePickerRangeSplit.types';

export const DatePickerRangeSplit = forwardRef<HTMLInputElement, DatePickerRangeSplitProps>(
	(
		{
			className,
			value = [],
			minDate = '',
			maxDate = '',
			disabled = false,
			dataTestId = 'datepicker',
			disabledStartDate = false,
			disabledEndDate = false,
			multiselect = false,
			onFocus,
			onChange,
			onBlur,
			onClose,
			onOpen,
			onClickSelectDates,
			fullWidth,
			mobileView,
			excludeDate,
			customViewDate,
			initialViewDate,
			holidaysDate,
			dropdownClassName,
			enableImaskConfig,
			maskConfig,
			enableTimePicker,
			overlayScroll = true,
			shouldRenderOverlay,
			overlayClassName,
			alignDropDown,
			customizeDay,
			hideDropDown = false,
			timeZone,
			showAdjacentMonthDays,
			allowAdjacentMonthSelection,
			presetPeriods,
			onPresetPeriodSelect,
			clearOnExcludedDateClose = true,
			datepickerRef: externalDatepickerRef,
			...restProps
		},
		forwardedRef,
	) => {
		const internalDatepickerRef = useRef<HTMLDivElement>(null);
		const datepickerRef = externalDatepickerRef || internalDatepickerRef;

		const prevValue = usePrevious(value);

		const inputRef1 = useRef<HTMLInputElement>(null);
		const inputRef2 = useRef<HTMLInputElement>(null);

		const {
			isOpen,
			open,
			close,
			toggle,
			selectDate,
			setIsOpen,
			inputValue,
			setInputValue,
			handleChange,
			handleInputFocus,
			dropdownMenuProps,
			handleInputBlur,
		} = useDatePicker({
			value,
			onChange,
			onOpen,
			onClose,
			mode: 'rangeSplit',
			multiselect,
			disabledStartDate,
			disabledEndDate,
			prevValue,
			enableTimePicker,
			timeZone,
			datepickerRef,
			mobileView,
			dropdownClassName,
			onBlur,
			overlayScroll,
			shouldRenderOverlay,
			overlayClassName,
			alignDropDown,
		});

		// Определяем дату для отображения в календаре
		const getViewDate = () => {
			// Если есть значение, используем customViewDate (для обратной совместимости)
			if (value && value.length > 0 && (value[0] || value[1])) {
				return customViewDate;
			}
			// Если значения нет, приоритет у initialViewDate
			return initialViewDate || customViewDate;
		};

		const handleCloseDropdown = () => {
			const startVal = inputRef1.current?.value ?? '';
			const endVal = inputRef2.current?.value ?? '';
			const needClear = shouldClearOnCloseSplitInputs(
				startVal,
				endVal,
				inputValue as [string, string],
				enableImaskConfig,
				enableTimePicker,
				excludeDate,
				clearOnExcludedDateClose,
			);
			if (needClear) {
				setInputValue(['', '']);
				handleChange(['', '']);
			}
		};

		const handleCalendarClose = useCallback((): void => {
			if (onClickSelectDates) {
				return;
			}
			if (!mobileView) {
				close();
			}
		}, [mobileView, onClickSelectDates]);

		useEffect(() => {
			if (isOpen && disabled) {
				handleCalendarClose();
			}
		}, [disabled, handleCalendarClose, isOpen]);

		const handleMaskInputStartDateChange = (updatedInputValue: string): void => {
			const maskedDate = maskRuDate(updatedInputValue, !!enableTimePicker);
			const newDate = isFilledDate(maskedDate, { pattern: RU_FORMAT_PATTERN }) ? maskedDate : EMPTY_DATE;

			// Обновляем inputValue для корректного отображения маски
			setInputValue([updatedInputValue, inputValue[1]]);

			const formatedDate = formatDateToISOWithTimeZone(newDate, '00', '00', '00', !!enableTimePicker);
			if (excludeDate && !excludeDate(new Date(formatedDate))) {
				handleChange([formatedDate, EMPTY_DATE]);
			}

			if (!excludeDate) {
				handleChange([formatedDate, EMPTY_DATE]);
			}
		};

		const handleMaskInputEndDateChange = (updatedInputValue: string): void => {
			const maskedDate = maskRuDate(updatedInputValue, !!enableTimePicker);
			const newDate = isFilledDate(maskedDate, { pattern: RU_FORMAT_PATTERN }) ? maskedDate : EMPTY_DATE;

			// Обновляем inputValue для корректного отображения маски
			setInputValue([inputValue[0], updatedInputValue]);

			const formatedDate1 = formatDateToISOWithTimeZone(inputValue[0], '00', '00', '00', !!enableTimePicker);
			const formatedDate2 = formatDateToISOWithTimeZone(newDate, '00', '00', '00', !!enableTimePicker);

			if (excludeDate && !excludeDate(new Date(formatedDate1)) && !excludeDate(new Date(formatedDate2))) {
				handleChange([formatedDate1, formatedDate2]);
			}

			if (!excludeDate) {
				handleChange([formatedDate1, formatedDate2]);
			}
		};

		const handleInputStartDateChange = (event: ChangeEvent<HTMLInputElement>): void => {
			const { value: updatedInputValue } = event.target;

			const maskedDate = maskDate(updatedInputValue);
			const newDate = isFilledDate(maskedDate, { pattern: RU_FORMAT_PATTERN }) ? maskedDate : EMPTY_DATE;

			setInputValue([maskDate(updatedInputValue), EMPTY_DATE]);
			handleChange([formatDateToISOWithTimeZone(newDate, '00', '00', '00', enableTimePicker), EMPTY_DATE]);
		};

		const handleInputEndDateChange = (event: ChangeEvent<HTMLInputElement>): void => {
			const { value: updatedInputValue } = event.target;

			const maskedDate = maskDate(updatedInputValue);
			const newDate = isFilledDate(maskedDate, { pattern: RU_FORMAT_PATTERN }) ? maskedDate : EMPTY_DATE;

			setInputValue([inputValue[0], maskDate(updatedInputValue)]);
			handleChange([
				formatDateToISOWithTimeZone(inputValue[0], '00', '00', '00', enableTimePicker),
				formatDateToISOWithTimeZone(newDate, '00', '00', '00', enableTimePicker),
			]);
		};

		const handleCalendarIconClick = (): void => {
			isOpen ? handleCalendarClose() : open();
		};

		const rightIcon = (disabled: boolean): React.JSX.Element => (
			<IconButton
				size="medium"
				iconName={Icons.Calendar}
				onClick={disabled ? undefined : handleCalendarIconClick}
				disabled={disabled}
				type="button"
			/>
		);

		const saveDatesOnClick = onClickSelectDates
			? (): void => {
					handleCalendarClose();
					onClickSelectDates();
				}
			: undefined;

		const handlePresetSelect = (range: [string, string]): void => {
			selectDate(range);
			onPresetPeriodSelect?.(range);
		};

		return (
			<div
				ref={datepickerRef}
				className={classNames(
					'dsb_datepicker dsb_datepicker-range-split',
					fullWidth && 'dsb_datepicker__full-width',
					mobileView && 'dsb_datepicker-range-split__mobile',
					className,
				)}
				data-test-id={dataTestId}
				data-testid="DatePickerRangeSplit"
			>
				<div>
					{enableImaskConfig ? (
						<MaskField
							{...restProps}
							maskConfig={maskConfig || (enableTimePicker ? defaultMaskConfigTime : defaultMaskConfig)}
							ref={inputRef1}
							value={inputValue[0]}
							disabled={disabled || disabledStartDate || multiselect}
							endAdornment={rightIcon((!multiselect && disabled) || disabledStartDate)}
							onBlur={handleInputBlur}
							onFocus={handleInputFocus}
							onChange={handleMaskInputStartDateChange}
							fullWidth={fullWidth}
						/>
					) : (
						<TextField
							{...restProps}
							ref={inputRef1}
							value={inputValue[0]}
							disabled={disabled || disabledStartDate || multiselect}
							endAdornment={rightIcon((!multiselect && disabled) || disabledStartDate)}
							onBlur={handleInputBlur}
							onFocus={handleInputFocus}
							onChange={handleInputStartDateChange}
							fullWidth={fullWidth}
						/>
					)}
					{!mobileView && <span>-</span>}
					{enableImaskConfig ? (
						<MaskField
							{...restProps}
							maskConfig={maskConfig || (enableTimePicker ? defaultMaskConfigTime : defaultMaskConfig)}
							ref={inputRef2}
							value={inputValue[1]}
							disabled={disabled || disabledEndDate || multiselect}
							endAdornment={rightIcon((!multiselect && disabled) || disabledEndDate)}
							onBlur={handleInputBlur}
							onFocus={handleInputFocus}
							onChange={handleMaskInputEndDateChange}
							fullWidth={fullWidth}
						/>
					) : (
						<TextField
							{...restProps}
							ref={inputRef2}
							value={inputValue[1]}
							disabled={disabled || disabledEndDate || multiselect}
							endAdornment={rightIcon((!multiselect && disabled) || disabledEndDate)}
							onBlur={handleInputBlur}
							onFocus={handleInputFocus}
							onChange={handleInputEndDateChange}
							fullWidth={fullWidth}
						/>
					)}
				</div>
				{isOpen && !hideDropDown && (
					<NewDropdownMenu {...dropdownMenuProps} onClose={handleCloseDropdown}>
						<CalendarRange
							value={value}
							minValue={minDate}
							maxValue={maxDate}
							disabledStartDate={disabledStartDate}
							disabledEndDate={disabledEndDate}
							datepickerRef={datepickerRef}
							onSelectDate={selectDate}
							dataTestId={`${dataTestId}-calendar`}
							multiselect={multiselect}
							onClickSelectDates={saveDatesOnClick}
							mobileView={mobileView}
							excludeDate={excludeDate}
							customViewDate={customViewDate}
							initialViewDate={initialViewDate}
							holidaysDate={holidaysDate}
							customizeDay={customizeDay}
							outputDateFormat={enableTimePicker ? "yyyy-MM-dd'T'HH:mm:ss'Z'" : 'yyyy-MM-dd'}
							presetPeriods={presetPeriods}
							onPresetPeriodSelect={handlePresetSelect}
							timeZone={timeZone}
							showAdjacentMonthDays={showAdjacentMonthDays}
							allowAdjacentMonthSelection={allowAdjacentMonthSelection}
						/>
					</NewDropdownMenu>
				)}
			</div>
		);
	},
);
